// Return themes filtered for a learner level. Each level inherits all easier
// levels — a junior player still sees elementary content, and a senior player
// sees everything below them too.
//   forLevel('elementary') -> diff 0-2 only (Grade 3-6 friendly).
//   forLevel('junior')     -> diff 0-4 (elementary + junior).
//   forLevel('senior')     -> entire bank (elementary + junior + senior G10-AST).
//   forLevel()             -> raw themes, no filtering.
const SENIOR_LEVELS = ['senior-G10', 'senior-G11', 'senior-G12', 'senior-AST'];
window.QUESTION_BANK.forLevel = function (level) {
    if (!['elementary', 'junior', 'senior'].includes(level)) return this.themes;
    let allowed;
    if (level === 'elementary')   allowed = new Set(['elementary']);
    else if (level === 'junior')  allowed = new Set(['elementary', 'junior']);
    else                          allowed = new Set(['elementary', 'junior', ...SENIOR_LEVELS]);
    return this.themes.map(t => ({
        ...t,
        words: t.words.filter(w => allowed.has(w.level || 'junior')),
        grammar: t.grammar.filter(g => allowed.has(g.level || 'junior')),
    }));
};
